function StatIcon({ icon }) {
  if (icon === "database") {
    return <span className="portal-icon-stack">◫</span>
  }

  if (icon === "survey") {
    return <span className="portal-icon-stack">☰</span>
  }

  if (icon === "product") {
    return <span className="portal-icon-stack">✦</span>
  }

  return <span className="portal-icon-stack">▣</span>
}

