import { useMemo, useState } from "react"
import { Link } from "react-router-dom"
import { contentItems, contentTabs, portalMetrics } from "../data/portalContent"

function OpenData() {
  const [activeTab, setActiveTab] = useState("Semua")

  const filteredItems = useMemo(() => {
    if (activeTab === "Semua") {
      return contentItems
    }

    return contentItems.filter(
      (item) => item.category === activeTab || item.type === activeTab,
    )
  }, [activeTab])

  return (
    <div className="open-data-page">
      <section className="open-data-hero">
        <div className="open-data-hero__content">
          <span className="open-data-hero__eyebrow">Portal Konten Terbuka</span>
          <h1>Jelajahi data, visualisasi, dan publikasi Kota Tangerang dalam satu ruang.</h1>
          <p>
            Halaman ini dirancang agar pencarian konten terasa lebih cepat, lebih rapi,
            dan lebih nyaman dibaca di desktop maupun mobile.
          </p>

          <div className="open-data-hero__actions">
            <a href="#open-data-collection" className="btn btn-primary">
              Mulai Jelajahi
            </a>
            <span className="open-data-hero__hint">
              Konten terbaru diperbarui secara berkala untuk kebutuhan analisis dan publikasi.
            </span>
          </div>
        </div>

        <div className="open-data-hero__panel" aria-hidden="true">
          <div className="open-data-hero__panel-card">
            <span className="open-data-hero__panel-kicker">Sorotan Minggu Ini</span>
            <strong>8 konten unggulan</strong>
            <p>Dataset, infografis, analisis, dan peta tematik yang paling sering diakses.</p>
          </div>
          <div className="open-data-hero__panel-orbit open-data-hero__panel-orbit--one" />
          <div className="open-data-hero__panel-orbit open-data-hero__panel-orbit--two" />
          <div className="open-data-hero__panel-grid">
            {portalMetrics.slice(0, 3).map((metric) => (
              <article className="open-data-hero__mini-stat" key={metric.label}>
                <span>{metric.label}</span>
                <strong>{metric.value}</strong>
              </article>
            ))}
          </div>
        </div>
      </section>

      <section className="gov-metric-bar gov-metric-bar--top">
        {portalMetrics.map((metric) => (
          <article className="gov-metric-item" key={metric.label}>
            <div className="gov-metric-item__icon">
              <span className="portal-icon-stack">{metric.value}</span>
            </div>
            <div>{metric.label}</div>
          </article>
        ))}
      </section>

      <section className="open-data-toolbar" id="open-data-collection">
        <div className="open-data-toolbar__intro">
          <span className="open-data-toolbar__eyebrow">Filter Konten</span>
          <h2>Koleksi Open Data</h2>
          <p>Pilih kategori konten untuk menampilkan topik yang paling relevan.</p>
        </div>

        <div className="open-data-toolbar__tabs">
          {contentTabs.map((tab) => (
            <button
              key={tab}
              className={`open-data-tab ${activeTab === tab ? "is-active" : ""}`}
              type="button"
              onClick={() => setActiveTab(tab)}
            >
              {tab}
            </button>
          ))}
        </div>

        <div className="open-data-toolbar__aside">
          <div className="open-data-toolbar__count">
            <strong>{filteredItems.length}</strong>
            <span>konten tampil</span>
          </div>

          <select className="form-select open-data-toolbar__select" defaultValue="latest">
            <option value="latest">Tanggal Terbaru</option>
            <option value="popular">Paling Populer</option>
            <option value="a-z">A-Z</option>
          </select>
        </div>
      </section>

      <section className="open-data-grid">
        {filteredItems.map((item, index) => (
          <article className="open-data-card" key={item.id}>
            <div className="open-data-card__topline">
              <span className="open-data-card__date">{item.date}</span>
              <span className="open-data-card__status">Tersedia</span>
            </div>

            <div className={`open-data-card__visual tone-${item.imageTone}`}>
              <div className="open-data-card__poster">
                <div className="open-data-card__poster-mark" />
                <div className="open-data-card__poster-line" />
                <div className="open-data-card__poster-line open-data-card__poster-line--short" />
              </div>
            </div>

            <div className="open-data-card__meta">
              <span className="open-data-card__tag">{item.type}</span>
              <span className="open-data-card__tag open-data-card__tag--soft">{item.category}</span>
            </div>

            <h3>{item.title}</h3>
            <p>{item.summary}</p>

            <div className="open-data-card__footer">
              <span className="open-data-card__footer-label">Lihat ringkasan dan detail data</span>
              <Link
                to={`/dataset/${index % 3 === 0 ? "kependudukan-2026" : index % 3 === 1 ? "umkm-aktif" : "layanan-kesehatan"}`}
                className="btn btn-light"
              >
                Buka Detail
              </Link>
            </div>
          </article>
        ))}
      </section>
    </div>
  )
}

export default OpenData
