import { useEffect, useMemo, useState } from "react"
import { Link } from "react-router-dom"
import { fetchDatasets } from "../utils/ckan"

const statusOptions = ["Semua", "Selesai", "Sedang Diverifikasi", "Belum Tersedia"]

function formatMonthYear(value) {
  if (!value) {
    return "-"
  }

  const date = new Date(value)

  if (Number.isNaN(date.getTime())) {
    return "-"
  }

  return new Intl.DateTimeFormat("id-ID", {
    month: "long",
    year: "numeric",
  }).format(date)
}

function mapStatus(dataset) {
  if (dataset.state === "active") {
    return "Selesai"
  }

  if (dataset.state === "draft") {
    return "Sedang Diverifikasi"
  }

  return "Belum Tersedia"
}

function normalizeDataset(dataset) {
  return {
    id: dataset.id,
    name: dataset.name,
    title: dataset.title || dataset.name || "Tanpa judul",
    releaseDate: formatMonthYear(dataset.metadata_modified || dataset.metadata_created),
    releaseRaw: dataset.metadata_modified || dataset.metadata_created || "",
    status: mapStatus(dataset),
  }
}

function ReleaseDataset() {
  const [datasets, setDatasets] = useState([])
  const [search, setSearch] = useState("")
  const [selectedMonth, setSelectedMonth] = useState("Semua")
  const [selectedStatus, setSelectedStatus] = useState("Semua")
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState("")

  useEffect(() => {
    setLoading(true)
    setError("")

    fetchDatasets()
      .then((results) => {
        setDatasets(results.map(normalizeDataset))
      })
      .catch(() => {
        setError("Gagal memuat dataset dari CKAN.")
      })
      .finally(() => {
        setLoading(false)
      })
  }, [])

  const monthOptions = useMemo(() => {
    const months = datasets.map((dataset) => dataset.releaseDate).filter((value) => value && value !== "-")
    return ["Semua", ...new Set(months)]
  }, [datasets])

  const filteredDatasets = useMemo(() => {
    return datasets.filter((dataset) => {
      const matchesMonth = selectedMonth === "Semua" || dataset.releaseDate === selectedMonth
      const matchesStatus = selectedStatus === "Semua" || dataset.status === selectedStatus
      const matchesSearch =
        search.trim() === "" || dataset.title.toLowerCase().includes(search.toLowerCase())

      return matchesMonth && matchesStatus && matchesSearch
    })
  }, [datasets, search, selectedMonth, selectedStatus])

  return (
    <div className="release-page">
      <div className="release-breadcrumb">
        <Link to="/">Home</Link>
        <span>/</span>
        <strong>Jadwal rilis dataset</strong>
      </div>

      <section className="gov-home__section">
        <div className="gov-section-title">
          <span className="gov-section-title__bar" />
          <h2>Jadwal Rilis</h2>
        </div>

        <div className="release-filters">
          <select
            className="form-select"
            value={selectedMonth}
            onChange={(event) => setSelectedMonth(event.target.value)}
          >
            {monthOptions.map((month) => (
              <option key={month} value={month}>
                {month}
              </option>
            ))}
          </select>

          <select
            className="form-select"
            value={selectedStatus}
            onChange={(event) => setSelectedStatus(event.target.value)}
          >
            {statusOptions.map((status) => (
              <option key={status} value={status}>
                {status}
              </option>
            ))}
          </select>

          <input
            className="form-control"
            placeholder="Cari Nama Dataset"
            value={search}
            onChange={(event) => setSearch(event.target.value)}
          />
        </div>

        <div className="release-table-card">
          {loading ? (
            <div className="portal-empty-state">Memuat dataset dari CKAN...</div>
          ) : error ? (
            <div className="portal-empty-state">{error}</div>
          ) : (
            <>
              <div className="release-table">
                <div className="release-table__head">
                  <span>No</span>
                  <span>Judul</span>
                  <span>Jadwal Rilis</span>
                  <span>Status</span>
                  <span>Tautan Dataset</span>
                </div>

                {filteredDatasets.map((dataset, index) => (
                  <div className="release-table__row" key={dataset.id}>
                    <span>{index + 1}</span>
                    <span>{dataset.title}</span>
                    <span>{dataset.releaseDate}</span>
                    <span>
                      <span className={`release-status ${dataset.status === "Selesai" ? "is-done" : dataset.status === "Sedang Diverifikasi" ? "is-review" : "is-empty"}`}>
                        {dataset.status}
                      </span>
                    </span>
                    <span>
                      <Link to={`/dataset/${dataset.name}`} className="release-link">
                        Lihat Dataset
                      </Link>
                    </span>
                  </div>
                ))}
              </div>

              <div className="release-table__summary">Total Data: {filteredDatasets.length}</div>
            </>
          )}
        </div>
      </section>
    </div>
  )
}

export default ReleaseDataset
