import { useEffect, useMemo, useRef, useState } from "react"
import { Link, useLocation } from "react-router-dom"
import logoPortal from "../assets/img/logologin.png"

const navItems = [
  { to: "/", label: "Home", activeOn: ["/"] },
  { to: "/open-data", label: "Open Data", activeOn: ["/open-data"] },
  { to: "/open-data", label: "Statistik Sektoral", activeOn: [] },
  { to: "/open-data", label: "Visualisasi", activeOn: [] },
  { to: "/jadwal-rilis-dataset", label: "SPLD", activeOn: ["/jadwal-rilis-dataset"] },
  { to: "/open-data", label: "Tangerang Satu Data", activeOn: [] },
  { to: "/open-data", label: "Tangerang Global City", activeOn: [] },
  { to: "/open-data", label: "Bantuan", activeOn: [] },
]

const languageOptions = [
  { code: "id", label: "Indonesia", flag: "ID" },
  { code: "en", label: "English", flag: "EN" },
  { code: "ar", label: "Arabic", flag: "AR" },
  { code: "zh-CN", label: "Chinese", flag: "ZH" },
  { code: "ja", label: "Japanese", flag: "JP" },
]

function Navbar() {
  const location = useLocation()
  const [isLanguageOpen, setIsLanguageOpen] = useState(false)
  const [selectedLanguage, setSelectedLanguage] = useState("id")
  const languageMenuRef = useRef(null)

  const activeLanguage = useMemo(
    () =>
      languageOptions.find((item) => item.code === selectedLanguage) || languageOptions[0],
    [selectedLanguage],
  )

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (!languageMenuRef.current?.contains(event.target)) {
        setIsLanguageOpen(false)
      }
    }

    document.addEventListener("mousedown", handleClickOutside)

    return () => {
      document.removeEventListener("mousedown", handleClickOutside)
    }
  }, [])

  const applyLanguage = (languageCode) => {
    setSelectedLanguage(languageCode)
    setIsLanguageOpen(false)

    const combo = document.querySelector(".goog-te-combo")

    if (combo) {
      combo.value = languageCode === "id" ? "" : languageCode
      combo.dispatchEvent(new Event("change"))
    }
  }

  return (
    <header className="site-header">
      <nav className="navbar">
        <div className="container">
          <Link to="/" className="navbar-brand">
            <span className="navbar-brand__copy">
              <span className="navbar-brand__identity">
                <img src={logoPortal} alt="Logo Satu Data Tangerang" className="navbar-brand__logo" />
                <span className="navbar-brand__title">
                  <strong>Satu Data</strong>
                  <small>TANGERANG</small>
                </span>
              </span>
              <em>Portal data terbuka dan statistik sektoral kota</em>
            </span>
          </Link>

          <div className="navbar-nav" aria-label="Navigasi utama">
            {navItems.map((item) => {
              const active = item.activeOn.includes(location.pathname)

              return (
                <Link
                  key={`${item.label}-${item.to}`}
                  to={item.to}
                  className={`nav-link ${active ? "active" : ""}`}
                >
                  {item.label}
                </Link>
              )
            })}
          </div>

          <div className="navbar-tools">
            <div className="navbar-language" ref={languageMenuRef}>
              <button
                type="button"
                className="navbar-language__trigger"
                onClick={() => setIsLanguageOpen((value) => !value)}
                aria-expanded={isLanguageOpen}
                aria-label="Pilih bahasa"
              >
                <span className={`navbar-language__flag navbar-language__flag--${activeLanguage.code}`}>
                  {activeLanguage.flag}
                </span>
                <span className="navbar-language__label">{activeLanguage.label}</span>
                <span className={`navbar-language__chevron ${isLanguageOpen ? "is-open" : ""}`}>
                  ^
                </span>
              </button>

              {isLanguageOpen && (
                <div className="navbar-language__menu">
                  {languageOptions.map((language) => (
                    <button
                      key={language.code}
                      type="button"
                      className={`navbar-language__option ${
                        language.code === selectedLanguage ? "is-active" : ""
                      }`}
                      onClick={() => applyLanguage(language.code)}
                    >
                      <span className={`navbar-language__flag navbar-language__flag--${language.code}`}>
                        {language.flag}
                      </span>
                      <span>{language.label}</span>
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div id="google_translate_element" className="google-translate-anchor" />
        </div>
      </nav>
    </header>
  )
}

export default Navbar
